                listener->on_data_available(this, guid, seq, seq, notify_single);
                if (notify_single)
                {
                    listener->onNewCacheChangeAdded(this, change);
                }
            }

            new_notification_cv_.notify_all();

            // statistics callback
            on_subscribe_throughput(payload_length);

            return true;
        }
    }

